function getSvgMarkup(value, fallbackKey = null) {
  const normalize = (input) => String(input || '').trim().toLowerCase();
  const key = normalize(value);
  const fallback = normalize(fallbackKey);

  const keys = Object.keys(LOCAL_SVG_ASSETS);
  const matchKey = keys.find((entry) => normalize(entry) === key);
  if (matchKey) {
    return LOCAL_SVG_ASSETS[matchKey];
  }

  const fallbackMatch = keys.find((entry) => normalize(entry) === fallback);
  if (fallbackMatch) {
    return LOCAL_SVG_ASSETS[fallbackMatch];
  }

  return '';
}

class ProgressHeader extends BaseComponent {
  static get observedAttributes() {
    return ['text', 'progress'];
  }

  constructor(props = {}) {
    super();
    if (props && typeof props === 'object') {
      if (Object.prototype.hasOwnProperty.call(props, 'text')) {
        this.text = props.text;
      }
      if (Object.prototype.hasOwnProperty.call(props, 'progress')) {
        this.progress = props.progress;
      }
    }
  }

  connectedCallback() {
    this.render();
  }

  attributeChangedCallback(name, oldValue, newValue) {
    if (oldValue === newValue) {
      return;
    }
    if (name === 'text' || name === 'progress') {
      this.render();
    }
  }

  get text() {
    return this.getAttribute('text') || '';
  }

  set text(value) {
    this.setAttribute('text', String(value || ''));
  }

  get progress() {
    const parsed = Number.parseInt(this.getAttribute('progress') || '1', 10);
    if (Number.isNaN(parsed)) {
      return 1;
    }
    return Math.min(7, Math.max(1, parsed));
  }

  set progress(value) {
    const parsed = Number.parseInt(String(value), 10);
    const clamped = Number.isNaN(parsed) ? 1 : Math.min(7, Math.max(1, parsed));
    this.setAttribute('progress', String(clamped));
  }

  buildProgressSvgMarkup() {
    const baseSvgText = getSvgMarkup('progress-bar', 'progress-bar');
    if (!baseSvgText) {
      return '';
    }

    const parser = new DOMParser();
    const doc = parser.parseFromString(baseSvgText, 'image/svg+xml');
    const svg = doc.documentElement;
    const rects = Array.from(svg.querySelectorAll('rect'));

    rects.forEach((rect, index) => {
      rect.setAttribute('fill', index < this.progress ? '#f9cf20' : '#ffffff');
    });

    svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
    return new XMLSerializer().serializeToString(svg);
  }

  render() {
    this.clear();

    const title = this.createElement('div', {
      innerText: this.text,
      style: {
        fontSize: '16px',
        fontWeight: '700',
        color: '#313131',
        lineHeight: '1.1',
        textAlign: 'center',
        whiteSpace: 'nowrap',
        overflow: 'hidden',
        textOverflow: 'ellipsis'
      }
    });

    const subtitle = this.createElement('div', {
      innerText: `stage ${this.progress}/8`,
      style: {
        marginTop: '4px',
        fontSize: '12px',
        color: '#6a6a6a',
        lineHeight: '1.1',
        textAlign: 'center'
      }
    });

    const titleBox = this.createElement('div', {
      style: {
        backgroundColor: '#ffffff',
        border: '1px solid #000000',
        borderRadius: '12px',
        padding: '8px 12px',
        boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)',
        boxSizing: 'border-box'
      }
    });
    titleBox.append(title, subtitle);

    const progressWrap = this.createElement('div', {
      innerHTML: this.buildProgressSvgMarkup(),
      style: {
        width: '100%',
        lineHeight: '0',
        padding: '0 2px'
      }
    });
    const progressSvg = progressWrap.querySelector('svg');
    if (progressSvg) {
      this.setStyles(progressSvg, {
        width: '100%',
        height: '20px',
        display: 'block'
      });
      progressSvg.setAttribute('role', 'img');
      progressSvg.setAttribute('aria-label', `Progress ${this.progress} of 7`);
    }

    this.appendChildren(this, [titleBox, progressWrap]);

    this.setHostStyles({
      display: 'grid',
      gap: '6px',
      //width: '50%',
      boxSizing: 'border-box'
    });
  }
}

customElements.define('progress-header', ProgressHeader);

export default ProgressHeader;
